insert or replace into LocalizedText
    (Language,      Tag,                                                                 Text)
values
    ("zh_Hans_CN",  "LOC_GREAT_PERSON_INDIVIDUAL_JNR_ARCHIMEDES_NAME",                  "阿基米德"),
    ("zh_Hans_CN",  "LOC_JNR_GREATPERSON_EUREKA_STRENGTH",                              "[ICON_TechBoosted] 尤里卡提供的科技值额外+3%。"),
    ("zh_Hans_CN",  "LOC_GREAT_PERSON_INDIVIDUAL_JNR_LI_BING_NAME",                     "李冰"),
    ("zh_Hans_CN",  "LOC_JNR_GREATPERSON_DAM_UNLOCK_MATHEMATICS",                       "解锁科技“数学”即可建造堤坝。建造堤坝时加速25%。堤坝为所在城市的沿河单元格+1 [ICON_Production] 生产力。"),
    ("zh_Hans_CN",  "LOC_GREAT_PERSON_INDIVIDUAL_JNR_MA_JUN_NAME",                      "马钧"),
    ("zh_Hans_CN",  "LOC_HD_GREATPERSON_GRANT_IZ_TIER1_BUILDING",                       "立即在该区域建造工作坊。[NEWLINE]工业区一级建筑+1 [ICON_PRODUCTION] 生产力。"),
    ("zh_Hans_CN",  "LOC_GREATPERSON_IMHOTEP_ACTIVE_JNR_UC",                            "建造奇观时提供55点 [ICON_Production] 生产力，对于远古和古典时代的奇观加倍。"),
    ("zh_Hans_CN",  "LOC_GREATPERSON_JAMES_WATT_ACTIVE",                         		"立即在该区域建造工作坊和工厂。[NEWLINE]工业区二级建筑+3 [ICON_PRODUCTION] 生产力。"),
    ("zh_Hans_CN",  "LOC_GREAT_PERSON_INDIVIDUAL_JNR_MARTINE_DE_BERTEREAU_NAME",        "玛蒂娜·德·贝尔特罗"),
    ("zh_Hans_CN",  "LOC_GREAT_PERSON_INDIVIDUAL_ZHANGHENG",                            "触发“工程”科技的 [ICON_TECHBOOSTED] 尤里卡，如果“工程”科技的 [ICON_TECHBOOSTED] 尤里卡已触发，则改为解锁该科技。"),
    ("zh_Hans_CN",  "GREATPERSON_1CLASSICALMEDIEVALTECHBOOSTS",                         "触发一个随机古典时代科技的 [ICON_TECHBOOSTED] 尤里卡。"),
    ("zh_Hans_CN",  "LOC_GREATPERSON_EUCLID_ACTIVE",                                    "触发“数学”科技的 [ICON_TECHBOOSTED] 尤里卡。该城可无视人口限制，多建造一个区域。"),
    -- history
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_JNR_ARCHIMEDES_CHAPTER_HISTORY_PARA_1",     "阿基米德（公元前287年—公元前212年），伟大的古希腊哲学家、百科式科学家、数学家、物理学家、力学家，静态力学和流体静力学的奠基人，并且享有“力学之父”的美称，阿基米德和高斯、牛顿并列为世界三大数学家。 阿基米德曾说过：“给我一个支点，我就能撬起整个地球。”"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_JNR_ARCHIMEDES_CHAPTER_HISTORY_PARA_2",     "阿基米德确立了静力学和流体静力学的基本原理。给出许多求几何图形重心，包括由一抛物线和其网平行弦线所围成图形的重心的方法。阿基米德证明物体在液体中所受浮力等于它所排开液体的重量，这一结果后被称为阿基米德原理。他还给出正抛物旋转体浮在液体中平衡稳定的判据。阿基米德发明的机械有引水用的水螺旋，能牵动满载大船的杠杆滑轮机械，能说明日食，月食现象的地球-月球-太阳运行模型。但他认为机械发明比纯数学低级，因而没写这方面的著作。阿基米德还采用不断分割法求椭球体、旋转抛物体等的体积，这种方法已具有积分计算的雏形。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_JNR_LI_BING_CHAPTER_HISTORY_PARA_1",        "李冰（约公元前3世纪）是战国时代秦国水利工程专家。公元前256年—前251年被秦昭王任为蜀郡（今成都一带）郡守，任蜀郡郡守时他主持设计并建造了成都北部的都江堰，泄岷江洪水且用之于灌溉，为成都平原成为天府之国奠定了非常重要的基础。他在蜀郡还主持兴办了其他水利工程，并修筑桥梁，在广都主持开凿盐井等，为开发成都平原、发展农业生产作出了重大贡献。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_JNR_LI_BING_CHAPTER_HISTORY_PARA_2",        "都江堰至今仍在使用，并被列为联合国教科文组织的世界遗产地。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_JNR_MA_JUN_CHAPTER_HISTORY_PARA_1",         "马钧，字德恒，三国时期魏国扶风（今陕西省兴平市）人，机械工程师、发明家和政治家。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_JNR_MA_JUN_CHAPTER_HISTORY_PARA_2",         "他最引人注目的发明是指向南方的战车，这是一种定向罗盘车，实际上没有磁力功能，而是通过使用差动齿轮（对以不同速度旋转的驱动轮施加等量的扭矩）来操作。正是由于这一革命性的装置（以及其他成就），马钧被称为当时最杰出的机械工程师和发明家之一（与早期东汉的张衡齐名）。在马钧之后，许多人重新发明了这个装置，包括天文学家和数学家祖冲之（429-500）。在后来的中世纪王朝时期，马钧的指向南方的战车与测量距离的里程表合二为一。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_JNR_MA_JUN_CHAPTER_HISTORY_PARA_3",         "他还改进了当时操作笨重的织绫机；发明一种由低处向高地引水的龙骨水车；制作出一种轮转式发石机，能连续发射石块，远至数百步；把木制原动轮装于木偶下面，叫做“水转百戏图”。此后，马钧还改制了诸葛连弩，对科学发展和技术进步做出了贡献。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_SI_MA_QIAN_CHAPTER_HISTORY_PARA_1",         "司马迁（前135或145-？）字子长，西汉左内史龙门人，是中国乃至世界上最伟大的历史学家之一。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_SI_MA_QIAN_CHAPTER_HISTORY_PARA_2",         "司马迁在汉景帝年间生于一个知识分子家庭。其父司马谈曾任太史令，在其影响下，司马迁在年少时就熟读史书。从二十岁开始，司马迁游历天下，足迹遍布庐山、会稽、大梁、鲁、离碓、长沙等等多地。两年后，司马迁回到长安入朝为官。到武帝元封元年，司马谈因病未能参与武帝泰山封禅，遂愤懑而死，死前向司马迁寄托了著作史书，延续司马家祖先太史官的任务。司马迁又曾学于汉儒董仲舒、孔安国，博采百家之长，以“究天人之际，通古今之变”的气魄，著成了《太史公书》，即《史记》，开创了中国史学编纂的纪传体范式，历代官方修史，无不遵循这一体例。武帝天汉二年，司马迁因为投降匈奴的李陵辩解而被捕下狱，在死刑和腐刑之间，他选择了“污及先人”的腐刑以延续著书立说的事业，他的这种品德也为后人所称道。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_SI_MA_QIAN_CHAPTER_HISTORY_PARA_3",         "在历史编纂方面，他的诸多贡献是开创性的。他开创了以人物传记作为线索的纪传体体例，善于用演绎的方式还原历史事件的情境。他遍历四方，善于从民间的遗迹和传言中提取有价值的史料。他还是世界上较早的开始书写民族史、经济史、思想文化史的作家。他在历史书写中还书写中下层人物及异国异族的历史，蕴含着朴素的平等思想。跟历史上很多著名的史学家一样，他也是善于秉笔直书历史事实的史家。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_SI_MA_QIAN_CHAPTER_HISTORY_PARA_4",         "在文学方面，司马迁也领风骚一时。在当时他的文学与辞赋家司马相如并称，鲁迅称其《史记》为“史家之绝唱，无韵之离骚”，既称赞了其史才，又赞扬了其文采。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_SI_MA_QIAN_CHAPTER_HISTORY_PARA_5",         "此外，司马迁还精通天文星象，他的天文学造诣主要体现在《史记·天官书》中，其中包含了中国最早的对星官（中国传统的对天球区域的划分）的记载。不过，司马迁还是存在将天体活动和社会人事对应起来的倾向，也无可避免的受到时代的局限。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_ZHUANG_ZHOU_CHAPTER_HISTORY_PARA_1",        "庄子（约前369-约286），名周，战国时期宋国蒙（主流说法为今河南商丘东北）人。战国中期思想家、哲学家、文学家，道家学派代表人物，与老子并称“老庄”。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_ZHUANG_ZHOU_CHAPTER_HISTORY_PARA_2",        "庄子被普遍的认为是道家先贤之一。他的哲学思想主要是“齐物”“逍遥”。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_ZHUANG_ZHOU_CHAPTER_HISTORY_PARA_3",        "齐物主张人应突破自我形躯的局限而对万物加以整体性把握。因此，庄子认为人的各种知识系统都是肤浅片面的，而一切事物归根到底都是相同的，没有什么差别，也没有是非、美丑、善恶、贵贱之分。而逍遥则是一种悠游自在的状态，是一种出世情结。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_ZHUANG_ZHOU_CHAPTER_HISTORY_PARA_4",        "对于庄子的思想，历来有着很多解释。有人认为他是原始的无政府主义者，也有人认为他的行为是一种嘲讽污浊世俗的行为艺术。无论怎么解释，他的逍遥依然成为一种代表精神只有的文化符号。而他自己本人也很擅长讲故事来表达他的思想。他的《庄子》本身除了是一部哲学巨著以外，也是一本优秀的寓言故事集。时至今日，他所创造的寓言故事仍然影响着一代代中国人。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_XU_FU_CHAPTER_HISTORY_PARA_1",              "徐福（生卒年不详）又作徐巿（注意不是市场的市），是战国末年和秦朝的方士。他在历史上第一次出现于《史记》，说因为秦始皇想追求长生不老，派徐福带三千童男童女向西航行“入海求仙人”。但是徐福在去了第一次以后无功而返。去第二次时，徐福发现了“平原广泽”，于是在当地称王，不在返回中原。这是《史记》描述，也是徐福故事的原始版本（至少是最接近原始版本的版本），然而，跟很多著名的传说母题一样，在后人不断的流传中，这个故事也在不断地变异。到隋唐时，因为日本开始学习唐朝政治文化，徐福的目的地也被与日本建立起了联系。自此之后，徐福东渡日本，建立国家的传说慢慢成形。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_XU_FU_CHAPTER_HISTORY_PARA_2",              "徐福其人其事是否真的存在？虽然《史记》的可信度较高，但是其语焉不详，并没有确切的提到徐福的明确去向。而后来有关徐福的传说的细节，后人附会的成分居多，日本国内有关徐福事迹的记载和纪念，也都是产生于中国文献传入以后。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_XU_FU_CHAPTER_HISTORY_PARA_3",              "徐福东渡日本之事，无论是否为真，都无可辩驳地成为了中日文化交流的重要符号，仍在发挥远超当时的人们预期的影响力。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_KINICH_KAN_BAHLAM_CHAPTER_HISTORY_PARA_1",  "基尼奇·坎·巴拉姆二世（635-702），也就是昌·巴鲁姆二世，是玛雅帕伦克城邦的阿哈乌（城邦世袭领主），继承了帕卡尔打造帕伦克盛世，利用帕伦克强势的国力建造了许多建筑，时至今日，访客还能从断壁残垣中窥见当年的盛况。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_KINICH_KAN_BAHLAM_CHAPTER_HISTORY_PARA_2",  "他继续着他父亲开始的用精美的艺术和建筑装饰帕伦克的雄心勃勃的项目；他对帕伦克城最重要的补充是十字神庙，这是十字神庙建筑群的中心作品。与基尼奇·坎·巴拉姆二世有关的纪念碑和文字是：十字神庙的石板和角椽上的太阳与带叶十字符号；铭文神庙的石板和门面；17号神庙的面板；死神之首雕像；约努塔面石板；十字神庙石碑。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_GUO_SHOU_JING_CHAPTER_HISTORY_PARA_1",      "郭守敬（1231-1316），字若思。邢州邢台县（今河北省邢台市信都区）人。元朝著名的天文学家、数学家、水利工程专家。早年师从刘秉忠、张文谦，官至太史令、昭文馆大学士、知太史院事，世称“郭太史”。元仁宗延祐三年（1316年），郭守敬逝世，享年八十六岁。著有《推步》《立成》等十四种天文历法著作。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_GUO_SHOU_JING_CHAPTER_HISTORY_PARA_2",      "郭守敬在天文、历法、水利和数学等方面都取得了卓越的成就。自至元十三年（1276年）起，他与许衡、王恂等奉命修订新历法，历时四年，制订出《授时历》，成为当时世界上最先进的一种历法，通行三百六十多年。为修订历法，郭守敬还改制、发明了简仪、高表等十二种新仪器。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_GUO_SHOU_JING_CHAPTER_HISTORY_PARA_3",      "至元元年（1264年），郭守敬奉命修浚西夏境内的古渠，更立闸堰，使当地农田得到灌溉。至元二十八年（1291年），郭守敬任都水监，负责修治元大都至通州的运河，耗时一年，完成了全部工程，定名通惠河，发展了南北交通和漕运事业。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_GUO_SHOU_JING_CHAPTER_HISTORY_PARA_4",      "1970年，国际天文学会以郭守敬的名字为月球上的一座环形山命名为“郭守敬环形山”。  1977年，国际小行星中心将小行星2012命名为“郭守敬小行星” 。中科院国家天文台也将国家重大科技基础设施LAMOST望远镜命名为“郭守敬天文望远镜”。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_HD_SANG_HONGYANG_CHAPTER_HISTORY_PARA_1",   "桑弘羊（前155年？-前80年），河南洛阳人，西汉时期政治家、经济学家、汉武帝的顾命大臣之一，官至御史大夫。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_HD_SANG_HONGYANG_CHAPTER_HISTORY_PARA_2",   "帝国运转需要巨额的财政开支，光靠农业税根本不够，如果不执行制度，问钱从哪里来？一旦遇到战争、灾荒等紧急事务，国库却空空如也，怎么办？如果中央在财政等各个方面不对地方形成压倒性的优势，一旦地方势力膨胀起兵造反，怎么办？这是汉代大臣桑弘羊留给一切政府的问题。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_HD_SANG_HONGYANG_CHAPTER_HISTORY_PARA_3",   "汉景帝前元中叶（一说前155年），桑弘羊出生于商业大都会洛阳的一户富商家庭。他13岁就开始在经济部门做官吏。到30多岁（汉武帝元狩三年，前120）时，桑弘羊就被汉武帝召见，之后就成为了汉朝政府一个重要的经济政策制定者。他几乎参与了所有汉武帝时汉朝重要的经济决策，主要包括盐铁官营、铸五铢钱、屯田西北等等。而他的行为基本上就是在实践地回答他提出的问题。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_HD_SANG_HONGYANG_CHAPTER_HISTORY_PARA_4",   "随着时间推移，他在武帝政府的地位越来越高，最后成为了托孤重臣之一，后来他跟历史上大多数权臣一样被控告谋反而处死了。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_HD_CROESUS_CHAPTER_HISTORY_PARA_1",         "克罗索斯（前585-前546），是小亚细亚西部吕底亚国的最后一位国王。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_HD_CROESUS_CHAPTER_HISTORY_PARA_2",         "吕底亚人当时是东地中海最著名的商人。希罗多德说他们是最早铸造金银货币的人，也是最早经营零售商业的人——当然，考虑到希罗多德向来因为道听途说而名声不嘉，他的记载仅供参考——他们还发明了棋类游戏。克罗索斯据记载是第一个下令发行纯金和纯银货币来规范货币流通的统治者。他也因此被认为是当时最富裕的人，几乎成为了代表有钱人的一个文化符号。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_HD_CROESUS_CHAPTER_HISTORY_PARA_3",         "他在位时期也扩张了吕底亚领土，与巴比伦、米底在西亚争霸。当雅利安人居鲁士在法尔斯崛起时，他向德尔菲神谕请求占卜这次战役的结果。他得到的结果是——一个帝国将毁灭。他欣然前去与波斯人作战，然而，毁灭的却是他自己的帝国。克罗索斯的结局说法不一，有人说他被居鲁士处死了，也有人说他被居鲁士聘为财政大臣。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_EMILIE_DU_CHATELET_CHAPTER_HISTORY_PARA_1", "约瑟夫·路易·拉格朗日（1736-1813），出生时名为朱塞佩·路易吉·拉格朗吉亚或朱塞佩·洛德维科·德·拉·格朗日·图尼尔，是一位法国籍意大利裔数学家和天文学家。拉格朗日曾为普鲁士的腓特烈大帝在柏林工作了20年，被腓特烈大帝称做“欧洲最伟大的数学家”，后受法国国王路易十六的邀请定居巴黎直至去世。拉格朗日一生才华横溢，在数学、物理和天文等领域做出了很多重大的贡献。他的成就包括著名的拉格朗日中值定理，创立了拉格朗日力学等等。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_EMILIE_DU_CHATELET_CHAPTER_HISTORY_PARA_2", "拉格朗日是18世纪一位十分重要的科学家，在数学、力学和天文学三个学科中都有历史性的重大贡献，但他主要是数学家。他最突出的贡献是在把数学分析的基础脱离几何与力学方面起了决定性的作用，使数学的独立性更为清楚，而不仅是其他学科的工具。同时在使天文学力学化、力学分析化上也起了历史性作用，促使力学和天文学（天体力学）更深入发展。在他的时代，分析学等分支刚刚起步，欠缺严密性和标准形式，但这不足以妨碍他取得大量的成果。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_EMILIE_DU_CHATELET_CHAPTER_HISTORY_PARA_3", "拉格朗日是变化微积分的创造者之一，他推导出了函数极值的欧拉-拉格朗日方程。他将这一方法扩展到包括可能的约束，得出了拉格朗日乘数。拉格朗日发明了被称为参数变化的微分方程求解方法，将微分计算应用于概率理论，并致力于代数方程的解决。他证明每个自然数都是四个平方的总和。他的论文《解析函数论》奠定了群论的一些基础，对伽罗瓦的理论起先导作用。在微积分方面，拉格朗日开发了一种新的插值g公式和泰勒定理。他研究了地球、太阳和月亮的三体问题（1764年）和木星卫星的运动（1766年），并于1772年发现了这个问题的特例解，产生了现在被称为拉格朗日的点。拉格朗日因将牛顿力学转变为分析学的一个分支——拉格朗日力学而最为著名。他将力学 “原理”作为变分微积分的简单结果提出。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_EMILIE_DU_CHATELET_CHAPTER_HISTORY_PARA_4", ""),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_JAMES_YOUNG_CHAPTER_HISTORY_PARA_1",        "尤斯图斯·冯·李比希男爵（1803年-1873）出生于今日德国黑森州前身黑森大公爵国的达姆施塔特，德国化学家，和吉森大学和慕尼黑大学的大学教授。李比希最重要的贡献在于农业和生物化学，他创立了有机化学。李比希认识到植物以盐的形式吸收重要的无机养分，通过他的研究，他创立了现代矿物肥料和农业化学的开端。作为大学教授他发明了现代实验室导向的教学方法，因为这一创新，他被誉为历史上最伟大的化学教育家之一。他发现了氮对于植物营养的重要性，因此也被称为“肥料工业之父”。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_JAMES_YOUNG_CHAPTER_HISTORY_PARA_2",        "李比希是19世纪最著名和最有成果的化学家，是有机化学、农业化学和营养生理学的奠基人。他的写作他对化学的发展的影响非常大。从1831年开始他与汉瑞默克一起编辑出版一份重要的化学和药学年报。他与他人一起出版了一本化学手册和一本有机化学手册。他还发表了许多关于改善农业操作的书籍。1840年他发表了他最重要的关于农业化学的书。为了普及化学知识，他从1841年开始不定期地在《奥格斯堡汇报》上发表科普性的、名为《化学邮件》的小文，获得很大欢迎。李比希是较早的将试验引入自然科学教学的人。通过他的研究他改善了化学中的分析方法，使得化学成为一门精确的学术。在最早的60名诺贝尔化学奖获得者中有42人是他的学生的学生。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_JAMES_YOUNG_CHAPTER_HISTORY_PARA_3",        "李比希的各种发明包罗万象，影响巨大。他的提出了无机化学中的根理论，建立了同分异构体概念。他发明了五球瓶等化学仪器、过磷酸钙等肥料、银制镜子、几种成本低廉的穷人营养品、发酵粉。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_MARY_LEAKEY_CHAPTER_HISTORY_PARA_1",        "罗莎琳·爱尔西·富兰克林（1920-1958），是一位英国物理化学家与晶体学家。她所做的研究，专注于DNA、病毒、煤炭与石墨等物质的结构。其中她所拍摄的DNA晶体绕射图片“照片51号”，以及关于此物质的相关数据，成为詹姆斯·华生与佛朗西斯·克里克解出DNA结构的关键线索。此后她也领导了关于烟草镶嵌病毒与小儿麻痹病毒的研究。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_MARY_LEAKEY_CHAPTER_HISTORY_PARA_2",        "在她所处的时代，人们对女性在学术上的能力仍然是轻视的，然而她却贡献颇丰。她对煤炭晶体结构的研究促进了煤化工进步，对烟草花叶病毒和脊髓灰质炎病毒的观测也促进了医学的发展。她做出的最大的贡献，是对DNA结构的发掘。她的观测为DNA双螺旋结构的发现奠定了基础，然而，她却因为长期接触X光观测仪器，年仅38岁就死于癌症，未能亲自发表DNA结构的发现。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_MARY_LEAKEY_CHAPTER_HISTORY_PARA_3",        ""),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_MARY_LEAKEY_CHAPTER_HISTORY_PARA_4",        ""),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_MARGARET_MEAD_CHAPTER_HISTORY_PARA_1",      "尤里乌斯·罗伯特·奥本海默（1904-1967），美国理论物理学家，曾于加利福尼亚大学伯克利分校任教物理。第二次世界大战期间，奥本海默领导洛斯阿拉莫斯实验室，其参与的曼哈顿计划最终研发出用于轰炸广岛与长崎的首批核武器，因此他被誉为“原子弹之父”。奥本海默曾经感叹道，人类史上首次核试验——1945年7月16日在新墨西哥州进行的三位一体核试验——让他不禁想到《薄伽梵歌》中的一句：“我现在成了死神，世界的毁灭者。”"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_MARGARET_MEAD_CHAPTER_HISTORY_PARA_2",      "战后，奥本海默在新成立的美国原子能委员会中担任总顾问委员会主席。他利用这一身份游说国际社会对核能进行管控，从而避免美国与苏联发生核军备竞赛以及防止核扩散。第二次红色恐慌期间，他公开发表的观点激怒了不少政治人士，他的安全许可也因此在1954年被撤销，意味着他无法再直接影响政治。奥本海默仍继续演讲、写作及研究物理。九年之后，美国总统约翰·肯尼迪授予奥本海默恩里科·费米奖（由继任总统林登·约翰逊颁发），奥本海默就此被平反。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_MARGARET_MEAD_CHAPTER_HISTORY_PARA_3",      "在物理方面，奥本海默的研究成果包括分子波函数的波恩–奥本海默近似法、电子和正子理论、核聚变中的奥本海默-菲利浦斯过程以及首次预测量子隧穿效应。他和学生的共同研究还对现代中子星和黑洞理论、量子力学、量子场论及宇宙射线相互作用等范畴有重大贡献。奥本海默作为一名老师，普及科学、一生志业，他在加州大学伯克利分校所建立的伯克利理论物理学中心是数一数二的理论物理学中心。二战后，他长期担任新泽西州普林斯顿高等研究院院长。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_STEPHANIE_KWOLEK_CHAPTER_HISTORY_PARA_1",   "莱纳斯·卡尔·鲍林（1901年－1994）是美国化学家，量子化学和结构生物学的先驱者之一。1954年因在化学键方面的工作取得诺贝尔化学奖，1963年因反对核弹在地面测试的行动获得1962年度的诺贝尔和平奖。 由于在1962年的决选过程中，挪威诺贝尔委员会认为当年的提名者均不符合阿尔弗雷德·诺贝尔遗嘱中所概述的标准。根据诺贝尔基金会的章程，在这种情况下，可以将诺贝尔奖保留到第二年，然后再应用该章程。 因此，一年后的1963年，莱纳斯·鲍林获得1962年诺贝尔和平奖，成为获得不同诺贝尔奖项的两人之一（另一人为玛丽·居里）；也是唯一的一位每次都是独立地获得诺贝尔奖的获奖人。其后他主要的行动为支持维他命C在医学的功用。鲍林被认为是20世纪对化学科学影响最大的人之一，他所撰写的《化学键的本质》被认为是化学史上最重要的著作之一。他以量子力学入手分析化学问题，结论却以直观、浅白的概念重新阐述，即便未受量子力学训练的化学家亦可利用准确的直观图像研究化学问题，影响至为深远，比如他所提出的许多概念：电负度、共振论、价键理论、混成轨域、蛋白质二级结构等概念和理论，如今已成为化学领域最基础和最广泛使用的观念。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_STEPHANIE_KWOLEK_CHAPTER_HISTORY_PARA_2",   ""),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_STEPHANIE_KWOLEK_CHAPTER_HISTORY_PARA_3",   ""),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_ABDUS_SALAM_CHAPTER_HISTORY_PARA_1",        "列夫·达维多维奇·朗道（1908－1968年），前苏联著名物理学家，凝聚态物理学的奠基人，苏联科学领军人之一，同时擅长理论物理多个分支领域，在理论物理里多个领域都有重大贡献。以惊人的物理直觉、杰出的物理研究成果、扎实的基本功、精炼的著作风格和严格的性格而为人熟知。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_ABDUS_SALAM_CHAPTER_HISTORY_PARA_2",        "他的成就包括独立地共同发现了量子力学中的密度矩阵法（与约翰d·冯s·诺依曼一起）、二磁体的量子力学理论、超流性理论、二阶相变理论、金兹堡-朗道超导理论、费米液体理论、解释等离子体物理中的朗道阻尼、量子电动力学中的朗道极、中微子的双组分理论、以及朗道的S矩阵奇点方程。他发展了超流性的数学理论，解释了温度低于2.17K（-270.98℃）的液态氦II的特性。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_ABDUS_SALAM_CHAPTER_HISTORY_PARA_3",        "他由于“关于凝聚态物质的开创性理论，特别是液氦”获得1962年的诺贝尔物理学奖，朗道当时由于身体原因，不能前往国外领奖。结果诺贝尔奖基金会打破了惯例，在历史上第一次不是在瑞典首都由国王授奖，而是由瑞典大使在莫斯科授予了朗道这一物理学研究的最高荣誉。1962年，仍活跃于研究前沿的朗道发生严重车祸，工作能力受损，身体状况大不如前，6年后去世。朗道去世多年后，阿列克谢·阿布里科索夫及维塔利·金兹堡凭借早年与朗道共同建立的超导体和超流体理论也于2003年获得诺贝尔物理学奖。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_HD_SANCTUS_LEO_CHAPTER_HISTORY_PARA_1",     "圣利奥一世，天主教四大教宗中的第一位--也是最具有传奇色彩的一位。毕竟，伟大的教宗不在少数，可是，敢于直面征服者而不落下风的，似乎只有这么一位。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_HD_SANCTUS_LEO_CHAPTER_HISTORY_PARA_2",     "440年，圣利奥接任教皇，在这之前，他已经是一个成熟的主教（虽然，成熟指的是宗教审判方面）。在接任教宗后，他强调教宗是圣彼得的继承者，自己有统治全教会的权力。而在445年，他通过罗马皇帝的敕令成功将自己的期盼变成现实，从此，教宗作为天主教最高统治者的地位基本确立。此外，作为一位优秀的神学家，他的《大卷》也是订立迦克敦信经的主要文件。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_HD_SANCTUS_LEO_CHAPTER_HISTORY_PARA_3",     "当然，他最传奇的故事还是在452年，那一年，当时世界上最恐怖的征服者--匈奴王阿提拉正准备着摘下罗马作为他王冠上的明珠，千年古城岌岌可危。但是，在教宗单刀赴会的一夜之后，阿提拉却选择了撤军。当时，圣利奥到底对阿提拉说了什么？没人知道，但这等胆识和气魄，恐怕确实是天下少有。又过了三年，汪达尔也对罗马进行了进攻，这次，教宗却并没有成功阻止他们攻下罗马。在罗马被汪达尔劫掠两周后，教宗最终还是说服了侵略者阻止了更进一步的破坏，用实际行动证明了自己是罗马名副其实的保护者。"),
    ("zh_Hans_CN",  "LOC_PEDIA_GREATPEOPLE_PAGE_GREAT_PERSON_INDIVIDUAL_HD_SANCTUS_LEO_CHAPTER_HISTORY_PARA_4",     "461年，圣利奥一世去世。失去了埃提乌斯，马约里安，以及“罗马城的保护者”后，愿意为西罗马帝国付出的人越来越少，十五年后，西罗马帝国正式灭亡，中世纪开始，但这时，那位“罗马保护者”的影响才变得愈发壮大……");
